pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract LendingPool is ReentrancyGuard, Ownable {
    IERC20 public usdc;
    address public loanManager;

    mapping(address => uint256) public deposits;
    uint256 public totalDeposits;
    uint256 public totalBorrowed;

    uint256 public constant BPS_DENOMINATOR = 10000;

    constructor(address _usdc) Ownable(msg.sender) {
        usdc = IERC20(_usdc);
    }

    modifier onlyLoanManager() {
        require(msg.sender == loanManager, "not loan manager");
        _;
    }

    function setLoanManager(address manager) external onlyOwner {
        require(manager != address(0), "manager=0");
        loanManager = manager;
    }

    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "amount=0");
        require(usdc.transferFrom(msg.sender, address(this), amount), "transfer failed");
        deposits[msg.sender] += amount;
        totalDeposits += amount;
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(amount > 0, "amount=0");
        require(deposits[msg.sender] >= amount, "insufficient deposit");
        require(availableLiquidity() >= amount, "insufficient liquidity");
        deposits[msg.sender] -= amount;
        totalDeposits -= amount;
        require(usdc.transfer(msg.sender, amount), "transfer failed");
    }

    function lend(address to, uint256 amount) external nonReentrant onlyLoanManager {
        require(amount > 0, "amount=0");
        require(availableLiquidity() >= amount, "insufficient liquidity");
        totalBorrowed += amount;
        require(usdc.transfer(to, amount), "transfer failed");
    }

    function repay(uint256 amount) external nonReentrant onlyLoanManager {
        require(amount > 0, "amount=0");
        require(totalBorrowed >= amount, "repay>debt");
        totalBorrowed -= amount;
    }

    function utilizationRateBps() public view returns (uint256) {
        if (totalDeposits == 0) {
            return 0;
        }
        return (totalBorrowed * BPS_DENOMINATOR) / totalDeposits;
    }

    function getInterestRateBps() public view returns (uint256) {
        return utilizationRateBps() > 5000 ? 1000 : 500; // 10% or 5%
    }

    function availableLiquidity() public view returns (uint256) {
        return totalDeposits - totalBorrowed;
    }
}
","keccak256":"0x0cb23dfdc1920ad98b8e5f4d3d5738191dfe351ccc175bb8b1d863348745f8af","license":"MIT"},"contracts/LoanManager.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/utils/math/Math.sol";
import "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";
import "@uniswap/v3-periphery/contracts/interfaces/ISwapRouter.sol";
import "./ValuationEngine.sol";
import "./VestingAdapter.sol";
import "./LendingPool.sol";

interface IIdentityVerifier {
    function verifyProof(address user, bytes calldata proof) external returns (bool);
}

contract LoanManager is Ownable {
    ValuationEngine public valuation;
    VestingAdapter public adapter;
    LendingPool public pool;
    address public identityVerifier;
    uint256 public identityBoostBps;
    ISwapRouter public uniswapRouter;
    IERC20 public usdc;
    uint24 public poolFee;
    uint256 public liquidationSlippageBps;

    uint256 public constant BPS_DENOMINATOR = 10000;

    struct Loan {
        address borrower;
        uint256 principal;
        uint256 interest;
        uint256 collateralId;
        uint256 unlockTime;
        bool active;
    }

    mapping(uint256 => Loan) public loans;
    uint256 public loanCount;
    mapping(address => bool) public identityLinked;

    event LoanCreated(uint256 indexed loanId, address indexed borrower, uint256 amount);
    event LoanRepaid(uint256 indexed loanId, uint256 amount);
    event LoanSettled(uint256 indexed loanId, bool defaulted);
    event IdentityLinked(address indexed borrower, uint256 boostBps);
    event IdentityConfigUpdated(address verifier, uint256 boostBps);
    event LiquidationConfigUpdated(address router, uint24 poolFee, uint256 slippageBps);
    event CollateralLiquidated(
        uint256 indexed loanId,
        address indexed token,
        uint256 seizedAmount,
        uint256 usdcReceived
    );

    constructor(
        address _valuation,
        address _adapter,
        address _pool,
        address _identityVerifier,
        uint256 _identityBoostBps,
        address _uniswapRouter,
        uint24 _poolFee,
        uint256 _slippageBps
    ) Ownable(msg.sender) {
        valuation = ValuationEngine(_valuation);
        adapter = VestingAdapter(_adapter);
        pool = LendingPool(_pool);
        identityVerifier = _identityVerifier;
        identityBoostBps = _identityBoostBps;
        uniswapRouter = ISwapRouter(_uniswapRouter);
        poolFee = _poolFee;
        liquidationSlippageBps = _slippageBps;
        usdc = pool.usdc();
    }

    function setIdentityConfig(address verifier, uint256 boostBps) external onlyOwner {
        require(boostBps <= 2000, "boost too high");
        identityVerifier = verifier;
        identityBoostBps = boostBps;
        emit IdentityConfigUpdated(verifier, boostBps);
    }

    function setLiquidationConfig(
        address router,
        uint24 newPoolFee,
        uint256 slippageBps
    ) external onlyOwner {
        require(router != address(0), "router=0");
        require(slippageBps > 0 && slippageBps <= BPS_DENOMINATOR, "bad slippage");
        uniswapRouter = ISwapRouter(router);
        poolFee = newPoolFee;
        liquidationSlippageBps = slippageBps;
        emit LiquidationConfigUpdated(router, newPoolFee, slippageBps);
    }

    function linkIdentity(bytes calldata proof) external returns (bool) {
        require(identityVerifier != address(0), "no verifier");
        bool ok = IIdentityVerifier(identityVerifier).verifyProof(msg.sender, proof);
        require(ok, "invalid proof");
        identityLinked[msg.sender] = true;
        emit IdentityLinked(msg.sender, identityBoostBps);
        return true;
    }

    function createLoan(
        uint256 collateralId,
        address vestingContract,
        uint256 borrowAmount
    ) external {
        require(borrowAmount > 0, "amount=0");

        adapter.escrow(collateralId, vestingContract, msg.sender);
        (uint256 quantity, address token, uint256 unlockTime) = adapter.getDetails(collateralId);

        (uint256 pv, uint256 ltvBps) = valuation.computeDPV(quantity, token, unlockTime);
        if (identityLinked[msg.sender] && identityBoostBps > 0) {
            ltvBps = ltvBps + identityBoostBps;
            if (ltvBps > BPS_DENOMINATOR) {
                ltvBps = BPS_DENOMINATOR;
            }
        }
        uint256 maxBorrow = (pv * ltvBps) / BPS_DENOMINATOR;
        require(borrowAmount <= maxBorrow, "exceeds LTV");

        uint256 interestRateBps = pool.getInterestRateBps();
        uint256 interest = (borrowAmount * interestRateBps) / 10000;

        uint256 loanId = loanCount;
        loans[loanId] = Loan({
            borrower: msg.sender,
            principal: borrowAmount,
            interest: interest,
            collateralId: collateralId,
            unlockTime: unlockTime,
            active: true
        });
        loanCount += 1;

        pool.lend(msg.sender, borrowAmount);
        emit LoanCreated(loanId, msg.sender, borrowAmount);
    }

    function repayLoan(uint256 loanId, uint256 amount) external {
        Loan storage loan = loans[loanId];
        require(loan.active, "inactive");
        require(msg.sender == loan.borrower, "not borrower");
        require(amount > 0, "amount=0");

        require(usdc.transferFrom(msg.sender, address(pool), amount), "transfer failed");
        pool.repay(amount);

        uint256 remainingInterest = loan.interest;
        uint256 remainingPrincipal = loan.principal;

        if (amount >= remainingInterest) {
            loan.interest = 0;
            uint256 principalPaid = amount - remainingInterest;
            if (principalPaid >= remainingPrincipal) {
                loan.principal = 0;
                loan.active = false;
            } else {
                loan.principal = remainingPrincipal - principalPaid;
            }
        } else {
            loan.interest = remainingInterest - amount;
        }

        emit LoanRepaid(loanId, amount);
    }

    function settleAtUnlock(uint256 loanId) external {
        Loan storage loan = loans[loanId];
        require(loan.active, "inactive");
        require(block.timestamp >= loan.unlockTime, "not unlocked");

        uint256 remainingDebt = loan.principal + loan.interest;
        bool defaulted = remainingDebt > 0;
        (uint256 quantity, address token, ) = adapter.getDetails(loan.collateralId);

        if (!defaulted) {
            if (quantity > 0) {
                adapter.releaseTo(loan.collateralId, loan.borrower, quantity);
            }
        } else if (quantity > 0) {
            uint256 seizeAmount = _calculateSeizeAmount(token, remainingDebt);
            if (seizeAmount > quantity) {
                seizeAmount = quantity;
            }

            if (seizeAmount > 0) {
                adapter.releaseTo(loan.collateralId, address(this), seizeAmount);
                uint256 usdcReceived = _liquidate(
                    loanId,
                    token,
                    seizeAmount
                );
                if (usdcReceived > 0) {
                    uint256 repayAmount = usdcReceived;
                    uint256 poolDebt = pool.totalBorrowed();
                    if (repayAmount > poolDebt) {
                        repayAmount = poolDebt;
                    }
                    if (repayAmount > 0) {
                        require(
                            usdc.transfer(address(pool), repayAmount),
                            "usdc transfer failed"
                        );
                        pool.repay(repayAmount);
                    }
                }
            }

            if (quantity > seizeAmount) {
                adapter.releaseTo(loan.collateralId, loan.borrower, quantity - seizeAmount);
            }
        }

        loan.active = false;
        loan.principal = 0;
        loan.interest = 0;

        emit LoanSettled(loanId, defaulted);
    }

    function _liquidate(
        uint256 loanId,
        address token,
        uint256 seizeAmount
    ) internal returns (uint256 usdcReceived) {
        if (address(uniswapRouter) == address(0)) {
            return 0;
        }

        IERC20(token).approve(address(uniswapRouter), seizeAmount);
        uint256 minOut = _minUsdcOut(token, seizeAmount);

        ISwapRouter.ExactInputSingleParams memory params = ISwapRouter
            .ExactInputSingleParams({
                tokenIn: token,
                tokenOut: address(usdc),
                fee: poolFee,
                recipient: address(this),
                deadline: block.timestamp + 300,
                amountIn: seizeAmount,
                amountOutMinimum: minOut,
                sqrtPriceLimitX96: 0
            });

        usdcReceived = uniswapRouter.exactInputSingle(params);
        emit CollateralLiquidated(loanId, token, seizeAmount, usdcReceived);
    }

    function _minUsdcOut(
        address token,
        uint256 amountIn
    ) internal view returns (uint256) {
        AggregatorV3Interface priceFeed = valuation.priceFeed();
        (, int256 answer, , , ) = priceFeed.latestRoundData();
        require(answer > 0, "bad price");
        uint256 price = uint256(answer);

        uint8 priceDecimals = priceFeed.decimals();
        uint8 tokenDecimals = IERC20Metadata(token).decimals();
        uint8 usdcDecimals = IERC20Metadata(address(usdc)).decimals();

        uint256 usdValue = Math.mulDiv(amountIn, price, 10 ** tokenDecimals);
        uint256 expectedUsdc = Math.mulDiv(usdValue, 10 ** usdcDecimals, 10 ** priceDecimals);
        return (expectedUsdc * liquidationSlippageBps) / BPS_DENOMINATOR;
    }

    function _calculateSeizeAmount(
        address token,
        uint256 debtUsdc
    ) internal view returns (uint256) {
        if (address(token) == address(usdc)) {
            return debtUsdc;
        }

        AggregatorV3Interface priceFeed = valuation.priceFeed();
        (, int256 answer, , , ) = priceFeed.latestRoundData();
        require(answer > 0, "bad price");
        uint256 price = uint256(answer);

        uint8 priceDecimals = priceFeed.decimals();
        uint8 tokenDecimals = IERC20Metadata(token).decimals();
        uint8 usdcDecimals = IERC20Metadata(address(usdc)).decimals();

        uint256 tokenAmountAtOne = Math.mulDiv(
            debtUsdc,
            10 ** tokenDecimals,
            10 ** usdcDecimals
        );
        return Math.mulDiv(tokenAmountAtOne, 10 ** priceDecimals, price);
    }
}
","keccak256":"0x06b5c990201c8997073134a22e2be5ea6e57df5cd88bdeab9ffed9cdd5a94110","license":"MIT"},"contracts/ValuationEngine.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";
import "abdk-libraries-solidity/ABDKMath64x64.sol";

contract ValuationEngine is Ownable {
    using ABDKMath64x64 for int128;

    AggregatorV3Interface public priceFeed; // e.g., ETH/USD
    uint256 public riskFreeRate = 5; // percent, 5 = 5%
    uint256 public volatility = 50; // percent, 50 = 50%

    uint256 public constant BASE_LTV_BPS = 3000; // 30%
    uint256 public constant BPS_DENOMINATOR = 10000;

    constructor(address _priceFeed) Ownable(msg.sender) {
        priceFeed = AggregatorV3Interface(_priceFeed);
    }

    function setRiskFreeRate(uint256 newRate) external onlyOwner {
        require(newRate <= 20, "rate too high");
        riskFreeRate = newRate;
    }

    function setVolatility(uint256 newVol) external onlyOwner {
        require(newVol <= 100, "vol too high");
        volatility = newVol;
    }

    function computeDPV(
        uint256 quantity,
        address,
        uint256 unlockTime
    ) public view returns (uint256 pv, uint256 ltvBps) {
        require(quantity > 0, "quantity=0");
        require(unlockTime > block.timestamp, "already unlocked");

        (, int256 answer, , , ) = priceFeed.latestRoundData();
        require(answer > 0, "bad price");
        uint8 decimals = priceFeed.decimals();
        uint256 price = uint256(answer);

        uint256 baseValue = (quantity * price) / (10 ** decimals);

        // Time discount: exp(-rate * years)
        uint256 timeToUnlock = unlockTime - block.timestamp;
        int128 yearsToUnlock = ABDKMath64x64.divu(timeToUnlock, 365 days);
        int128 rate = ABDKMath64x64.divu(riskFreeRate, 100);
        int128 discount = ABDKMath64x64.exp(ABDKMath64x64.neg(rate.mul(yearsToUnlock)));

        // Monte Carlo-inspired conservatism
        int128 liquidity = ABDKMath64x64.divu(9, 10); // 0.9
        int128 shock = ABDKMath64x64.divu(95, 100); // 0.95
        int128 volPenalty = ABDKMath64x64.divu(volatility, 200); // 0.5 * vol
        int128 volAdj = ABDKMath64x64.sub(ABDKMath64x64.fromInt(1), volPenalty);
        if (volAdj < 0) {
            volAdj = ABDKMath64x64.fromInt(0);
        }

        int128 value64 = ABDKMath64x64.fromUInt(baseValue);
        int128 pv64 = value64.mul(discount).mul(liquidity).mul(shock).mul(volAdj);
        pv = ABDKMath64x64.toUInt(pv64);

        int128 ltv64 = ABDKMath64x64.fromUInt(BASE_LTV_BPS)
            .mul(liquidity)
            .mul(shock)
            .mul(volAdj);
        ltvBps = ABDKMath64x64.toUInt(ltv64);
        if (ltvBps > BPS_DENOMINATOR) {
            ltvBps = BPS_DENOMINATOR;
        }
    }
}
","keccak256":"0x0f738f707468f91cf5d4e2ded349e3eb124f7ad14be64a91ff7e9908333dc3b7","license":"MIT"},"contracts/VestingAdapter.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

interface IVestingWallet {
    function beneficiary() external view returns (address);
    function start() external view returns (uint256);
    function duration() external view returns (uint256);
    function released(address token) external view returns (uint256);
}

interface IVestingWalletToken is IVestingWallet {
    function token() external view returns (address);
    function totalAllocation() external view returns (uint256);
}

interface IVestingWalletTokenRelease is IVestingWalletToken {
    function releaseTo(address to, uint256 amount) external;
}

contract VestingAdapter is IERC721Receiver, Ownable {

    struct Collateral {
        address vestingContract;
        address token;
        uint256 totalAmount;
        uint256 unlockTime;
    }

    address public loanManager;
    mapping(uint256 => Collateral) public collaterals;
    mapping(uint256 => address) public vestingContracts;

    constructor() Ownable(msg.sender) {}

    function setLoanManager(address manager) external onlyOwner {
        require(manager != address(0), "manager=0");
        loanManager = manager;
    }

    function escrow(
        uint256 collateralId,
        address vestingContract,
        address borrower
    ) external {
        require(borrower != address(0), "borrower=0");
        require(
            msg.sender == borrower || msg.sender == loanManager,
            "not authorized"
        );
        require(vestingContract.code.length > 0, "not a contract");
        require(collaterals[collateralId].vestingContract == address(0), "id used");

        IVestingWalletToken vesting = IVestingWalletToken(vestingContract);
        require(vesting.beneficiary() == borrower, "not beneficiary");

        uint256 start = vesting.start();
        uint256 duration = vesting.duration();
        require(duration > 0, "duration=0");
        uint256 unlockTime = start + duration;
        require(unlockTime > block.timestamp, "already unlocked");

        address token = vesting.token();
        require(token != address(0), "token=0");
        uint256 total = vesting.totalAllocation();
        require(total > 0, "total=0");

        collaterals[collateralId] = Collateral({
            vestingContract: vestingContract,
            token: token,
            totalAmount: total,
            unlockTime: unlockTime
        });
        vestingContracts[collateralId] = vestingContract;
    }

    function getDetails(
        uint256 collateralId
    ) external view returns (uint256 quantity, address token, uint256 unlockTime) {
        Collateral memory c = collaterals[collateralId];
        require(c.vestingContract != address(0), "unknown collateral");

        uint256 releasedAmt = IVestingWallet(c.vestingContract).released(c.token);
        require(c.totalAmount >= releasedAmt, "released>total");
        quantity = c.totalAmount - releasedAmt;
        token = c.token;
        unlockTime = c.unlockTime;
    }

    function releaseTo(uint256 collateralId, address to, uint256 amount) external {
        require(msg.sender == loanManager, "not loan manager");
        require(to != address(0), "to=0");

        Collateral memory c = collaterals[collateralId];
        require(c.vestingContract != address(0), "unknown collateral");
        require(block.timestamp >= c.unlockTime, "not unlocked");
        require(amount > 0, "amount=0");

        IVestingWalletTokenRelease(c.vestingContract).releaseTo(to, amount);
    }

    function onERC721Received(
        address,
        address,
        uint256,
        bytes calldata
    ) external pure returns (bytes4) {
        return IERC721Receiver.onERC721Received.selector;
    }
}
